spec.expr:
sum by (route, status) (
  rate(stremio_double_subtitles_http_requests_total{
    route!="/metrics",
    route!="other",
    status!~"304|404"
  }[5m])
)

histogram_quantile(
  0.95,
  sum by (le, route) (
    rate(stremio_double_subtitles_http_request_duration_seconds_bucket{
      route!="/metrics",
      route!="other",
      status!~"304|404"
    }[5m])
  )
)
